						(
							slctn_pblanc_detail_id
							, slctn_pblanc_id
							, sj
							, detail_cn
							, creator_id
							, created_dt
							, updater_id
							, updated_dt
						)
				values	(
							#{slctnPblancDetailId}
							, #{slctnPblancId}
							, #{sj}
							, #{detailCn}
							, #{creatorId}
							, #{createdDt}
							, #{updaterId}
							, #{updatedDt}
						)

mapper.update:
/** UsptSlctnPblancDetailDao.update */
update uspt_slctn_pblanc_detail
set
	updater_id		= #{updaterId}
	, updated_dt	= #{updatedDt}
	, sj			= #{sj}
	, detail_cn		= #{detailCn}
where
	slctn_pblanc_detail_id = #{slctnPblancDetailId}
	and slctn_pblanc_id = #{slctnPblancId}

